import { createClient } from '@/lib/supabase/server';
import AddTranslationForm from '@/components/admin/AddTranslationForm';
import DeleteTranslationButton from '@/components/admin/DeleteTranslationButton';
import { Translation as TranslationType } from '@/types';
import { Pencil, Filter, Languages, Search, Globe, Link as LinkIcon, Type, FileText } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { getAdminPermissions } from '@/lib/supabase/permissions';

export const metadata = {
  title: 'Translations | Admin Portal',
};

interface PageProps {
  searchParams: Promise<{ q?: string }>;
}

export default async function AdminTranslationsPage({ searchParams }: PageProps) {
  const { q } = await searchParams;
  const supabase = await createClient();
  
  const { data: { user } } = await supabase.auth.getUser();
  const permissions = user ? await getAdminPermissions(user.id) : null;

  let query = supabase
    .from('translations')
    .select('*')
    .order('created_at', { ascending: false });

  if (q) {
    query = query.or(`translated_title.ilike.%${q}%,language.ilike.%${q}%,content_type.ilike.%${q}%`);
  }

  const { data: translations, error } = await query;

  if (error) {
    console.error('Error fetching translations for admin:', error);
  }

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-bold font-heading text-white mb-2 tracking-tight">
            Translations
          </h1>
          <p className="text-forest-light/60 font-medium italic">Bridge the gap between languages and cultures.</p>
        </div>
        <div className="flex items-center gap-3">
          <Button variant="outline" size="sm" leftIcon={<Filter size={16} />} className="border-white/10 text-white/70 hover:text-white hover:bg-white/5 backdrop-blur-md rounded-xl transition-all">
            Filter
          </Button>
          {permissions?.can_write && <AddTranslationForm />}
        </div>
      </div>

      {/* Search Bar */}
      <div className="relative group">
        <div className="absolute inset-0 bg-saffron/5 blur-2xl rounded-3xl opacity-0 group-focus-within:opacity-100 transition-opacity duration-500" />
        <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-white/30 group-focus-within:text-saffron transition-colors duration-300" size={20} />
        <form action="/admin/translations" method="GET" className="relative">
           <input 
            name="q"
            defaultValue={q}
            placeholder="Search translations by title, language or content type..." 
            className="w-full bg-white/5 border border-white/10 rounded-2xl py-5 pl-14 pr-6 text-white placeholder:text-white/20 focus:outline-none focus:border-saffron/40 focus:bg-white/[0.08] transition-all duration-300 backdrop-blur-xl shadow-2xl"
          />
        </form>
      </div>

      <div className="glass-card overflow-hidden border border-white/5 shadow-2xl rounded-3xl bg-white/[0.02] backdrop-blur-2xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/[0.03] border-b border-white/10 text-white/40 text-[10px] uppercase tracking-[0.2em] font-bold">
                <th className="px-8 py-6">Target Content</th>
                <th className="px-8 py-6">Language</th>
                <th className="px-8 py-6">Translated Title</th>
                <th className="px-8 py-6">Status</th>
                <th className="px-8 py-6 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {translations && translations.length > 0 ? (
                translations.map((translation: TranslationType) => (
                  <tr key={translation.id} className="hover:bg-white/[0.04] transition-all duration-300 group">
                    <td className="px-8 py-6">
                      <div className="flex flex-col gap-1.5">
                        <div className="flex items-center gap-2 font-bold text-white group-hover:text-saffron transition-colors text-lg tracking-tight">
                          <span className="capitalize">{translation.content_type}</span>
                        </div>
                        <div className="flex items-center gap-2 text-[10px] text-white/40 font-mono truncate max-w-[200px]">
                          <LinkIcon size={10} />
                          {translation.content_id}
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-2 text-sm text-white/60">
                        <Globe size={14} className="text-white/20" />
                        {translation.language}
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-2 text-sm text-white font-medium">
                          <Type size={14} className="text-white/20" />
                          {translation.translated_title || 'No Title'}
                        </div>
                        {translation.cultural_notes && (
                          <div className="text-[10px] text-white/30 italic flex items-center gap-1">
                            <FileText size={10} />
                            Has translator notes
                          </div>
                        )}
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <span className={`inline-flex items-center gap-2.5 text-[10px] font-extrabold uppercase tracking-widest ${
                        translation.status === 'published' ? 'text-emerald-400' : 'text-saffron'
                      }`}>
                        <span className={`w-2 h-2 rounded-full animate-pulse ${
                          translation.status === 'published' ? 'bg-emerald-400 shadow-[0_0_10px_rgba(52,211,153,0.4)]' : 'bg-saffron shadow-[0_0_10px_rgba(245,158,11,0.4)]'
                        }`} />
                        {translation.status}
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all duration-300 translate-x-2 group-hover:translate-x-0">
                        {permissions?.can_edit && (
                          <Button variant="ghost" size="icon" className="h-10 w-10 text-white/40 hover:text-white hover:bg-white/10 rounded-xl transition-all">
                            <Pencil size={18} />
                          </Button>
                        )}
                        {permissions?.can_delete && <DeleteTranslationButton id={translation.id} />}
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-8 py-32 text-center">
                    <div className="flex flex-col items-center max-w-sm mx-auto">
                      <div className="relative group/empty">
                        <div className="absolute inset-0 bg-saffron/20 blur-3xl rounded-full opacity-50 group-hover/empty:opacity-80 transition-opacity" />
                        <div className="relative w-24 h-24 bg-white/[0.03] rounded-[2rem] flex items-center justify-center mb-8 border border-white/10 backdrop-blur-xl shadow-inner">
                          <Languages size={40} className="text-white/20 group-hover/empty:text-saffron transition-colors" />
                        </div>
                      </div>
                      <h3 className="font-bold text-white text-2xl mb-3 tracking-tight">
                        {q ? 'No matching translations' : 'No translations yet'}
                      </h3>
                      <p className="text-white/40 mb-10 text-sm font-medium italic leading-relaxed">
                        {q 
                          ? `We couldn't find any translations matching "${q}". Try another search term.` 
                          : 'Expand the reach of wisdom by adding your first translation.'}
                      </p>
                      {permissions?.can_write && !q && <AddTranslationForm />}
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
